#include <bits/stdc++.h>
using namespace std;
const int N=35;
int n,dp[N][N][N],a[N][N];
int main()
{
	cin>>n;
	int x,y,z;
	while(cin>>x>>y>>z)
	{
		if(x==y&&y==z&&z==0) break;
		a[x][y]=z;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			for(int i2=1;i2<=n;i2++)
			{
				int j2=i+j-i2;
				if(j2<1) continue;
				dp[i][j][i2]=max(max(dp[i-1][j][i2-1],dp[i-1][j][i2]),max(dp[i][j-1][i2-1],dp[i][j-1][i2]))+a[i][j]+a[i2][j2];
				if(i==i2&&j==j2) dp[i][j][i2]-=a[i][j];
			}
		}
	}
	cout<<dp[n][n][n];
	return 0;
}
